#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);
use File::Basename;
use File::Spec;

print header('text/html; charset=UTF-8');

my $log_dir = '/var/log/myapp';
my $filename = param('logfile') || '';

print start_html(-title => 'Log Viewer');
print h1('Web-Based Log Viewer');

if (!$filename) {
    print p('No log file specified. Please provide a logfile parameter.');
    print end_html();
    exit;
}

$filename = basename($filename);
$filename =~ s/[^\w\.-]//g;

if ($filename !~ /\.log$/) {
    print p('Invalid log file. Only .log files are allowed.');
    print end_html();
    exit;
}

my $filepath = File::Spec->catfile($log_dir, $filename);

my $safe_log_dir = File::Spec->rel2abs($log_dir);
my $safe_filepath = File::Spec->rel2abs($filepath);

if (index($safe_filepath, $safe_log_dir) != 0) {
    print p('Access denied: Path traversal detected.');
    print end_html();
    exit;
}

if (!-e $safe_filepath) {
    print p("Log file not found: " . escapeHTML($filename));
    print end_html();
    exit;
}

if (!-f $safe_filepath) {
    print p("Not a valid file: " . escapeHTML($filename));
    print end_html();
    exit;
}

if (!-r $safe_filepath) {
    print p("Cannot read log file: " . escapeHTML($filename));
    print end_html();
    exit;
}

print h2("Viewing: " . escapeHTML($filename));
print start_pre();

open(my $FH, '<', $safe_filepath) or die "Cannot open file: $!";
